<?php $sections=json_decode(setting('homepage_section_order','["hero","banner","categories","products","benefits","cta"]'),true)?:['hero','banner','categories','products','benefits','cta'];$benefits=json_decode(setting('homepage_benefits_json','[]'),true)?:[];foreach($sections as $section):?>
<?php if($section==='hero'):?><?php $hero=setting('homepage_hero_image');?><section class="hero <?=$hero?'hero-with-image':''?>" <?php if($hero):?>style="--hero-image:url('<?=url('/media/homepage/'.$hero)?>')"<?php endif?>><div class="hero-copy"><span class="eyebrow"><?=e(setting('homepage_hero_eyebrow','Etalase untuk keseharian'))?></span><h1><?=e(setting('homepage_hero_title','Temukan barang yang terasa'))?> <em><?=e(setting('homepage_hero_accent','tepat.'))?></em></h1><p><?=e(setting('homepage_hero_description',setting('store_tagline')))?></p><a class="button button-light" href="<?=e(str_starts_with(setting('homepage_hero_cta_url','/produk'),'/')?url(setting('homepage_hero_cta_url','/produk')):setting('homepage_hero_cta_url'))?>"><?=e(setting('homepage_hero_cta_label','Jelajahi koleksi'))?></a></div><?php if(!$hero):?><div class="hero-mark"><span>Semua</span><strong>Kebutuhan</strong><i>01 — <?=date('Y')?></i></div><?php endif?></section>
<?php elseif($section==='banner'&&setting('homepage_banner_enabled','0')==='1'):?><?php $banner=setting('homepage_banner_image');?><section class="promo-banner" <?php if($banner):?>style="--banner-image:url('<?=url('/media/homepage/'.$banner)?>')"<?php endif?>><div><span class="eyebrow"><?=e(setting('homepage_banner_eyebrow'))?></span><h2><?=e(setting('homepage_banner_title'))?></h2><p><?=e(setting('homepage_banner_description'))?></p><a class="button button-light" href="<?=e(str_starts_with(setting('homepage_banner_cta_url','/produk'),'/')?url(setting('homepage_banner_cta_url','/produk')):setting('homepage_banner_cta_url'))?>"><?=e(setting('homepage_banner_cta_label','Lihat koleksi'))?></a></div></section>
<?php elseif($section==='categories'&&setting('homepage_categories_enabled','1')==='1'):?><section class="category-strip" id="kategori"><header><span class="eyebrow"><?=e(setting('homepage_categories_eyebrow','Belanja menurut kategori'))?></span><h2><?=e(setting('homepage_categories_title','Kategori pilihan'))?></h2></header><div><?php foreach($categories as $c):?><a href="<?=url('/kategori/'.$c['slug'])?>"><span><?=str_pad($c['total'],2,'0',STR_PAD_LEFT)?></span><?=e($c['name'])?></a><?php endforeach?></div></section>
<?php elseif($section==='products'&&setting('homepage_products_enabled','1')==='1'):?><section class="product-section"><header><div><span class="eyebrow"><?=e(setting('homepage_products_eyebrow','Baru di etalase'))?></span><h2><?=e(setting('homepage_products_title','Produk pilihan'))?></h2></div><a href="<?=url('/produk')?>"><?=e(setting('homepage_products_cta_label','Lihat semua'))?></a></header><div class="product-grid"><?php foreach($items as $x)require BASE_PATH.'/app/Views/storefront/product-card.php';?></div></section>
<?php elseif($section==='benefits'&&setting('homepage_benefits_enabled','1')==='1'&&$benefits):?><section class="benefits-section"><span class="eyebrow">Alasan memilih kami</span><h2><?=e(setting('homepage_benefits_title','Belanja dengan tenang'))?></h2><div><?php foreach($benefits as $benefit):?><article><i><?=e(['gift'=>'*','chat'=>'#','stock'=>'✓','truck'=>'→'][$benefit['icon']]??'•')?></i><h3><?=e($benefit['title'])?></h3><p><?=e($benefit['description'])?></p></article><?php endforeach?></div></section>
<?php elseif($section==='cta'&&setting('homepage_cta_enabled','0')==='1'):?><?php $ctaImage=setting('homepage_cta_image');?><section class="closing-cta" <?php if($ctaImage):?>style="--cta-image:url('<?=url('/media/homepage/'.$ctaImage)?>')"<?php endif?>><span class="eyebrow"><?=e(setting('homepage_cta_eyebrow'))?></span><h2><?=e(setting('homepage_cta_title'))?></h2><p><?=e(setting('homepage_cta_description'))?></p><a class="button button-light" href="<?=e(setting('homepage_cta_url'))?>"><?=e(setting('homepage_cta_label'))?></a></section><?php endif?>
<?php endforeach?>
